VALUES
  ('cpa-moex-01261', 'cpa', 'cpa-moex-104-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得基本稅額條例規定，營利事業於計算基本所得額時，得將經稽徵機關核定之證券交易損失，自發 生之次年度起幾年內，從當年度之證券交易所得中扣除？', '["三年", "五年", "七年", "十年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "6211ba8aa6e0", "answer_pdf_sha1": "351af3accf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01262', 'cpa', 'cpa-moex-104-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '黃小姐為我國境內居住之個人，其母（要保人）有兩份境內人壽保險契約，契約A之保險開始日為94年 2月1日，契約B之保險開始日為95年2月1日。其母於103年死亡，黃小姐（受益人）獲得契約A與 B之死亡保險給付分別為新臺幣3,100萬元與新臺幣2,000萬元，共新臺幣5,100萬元。請問依所得基本 稅額條例規定，該保險給付應計入個人基本所得之金額為新臺幣若干？', '["0元", "100萬元", "1,800萬元", "5,100萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "6211ba8aa6e0", "answer_pdf_sha1": "351af3accf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01263', 'cpa', 'cpa-moex-104-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '現行加值型及非加值型營業稅法規定，小規模營業人當期所支付之進項稅額，准予限額扣抵其當期應納 稅額，其主要之立法意旨何在？', '["為減輕其租稅負擔", "為減輕稽徵機關之作業負擔", "為配合營利事業所得稅稽徵程序之需要", "鼓勵其積極主動索取進項發票，以強化營業稅之勾稽作用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "6211ba8aa6e0", "answer_pdf_sha1": "351af3accf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01264', 'cpa', 'cpa-moex-104-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '營業人若發生營業登記之事項有變更，依加值型及非加值型營業稅法規定應於事實發生之日起幾天內， 向主管稽徵機關申請變更登記？', '["五日", "十日", "十五日", "二十日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "6211ba8aa6e0", "answer_pdf_sha1": "351af3accf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01265', 'cpa', 'cpa-moex-104-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，小規模營業人之營業稅繳納週期為何？', '["每個月繳納一次", "每2個月繳納一次", "每3個月繳納一次", "每6個月繳納一次"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "6211ba8aa6e0", "answer_pdf_sha1": "351af3accf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01266', 'cpa', 'cpa-moex-104-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '公益信託之受託人為公益信託舉辦義演所取得之收入，扣除支付該義演之必要費用後，全部供該公益事 業之用者，下列敘述何者正確？', '["可全數適用免稅", "可全數適用零稅率計稅", "應將義演收入扣除支付該義演之必要費用後之淨額依5%計稅，報繳營業稅", "仍應將義演收入依5%計稅，報繳營業稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "6211ba8aa6e0", "answer_pdf_sha1": "351af3accf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01267', 'cpa', 'cpa-moex-104-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '新強股份有限公司經營百貨業，某年四月份進貨取得載有進項稅額之憑證有香皂150,000元，毛巾50,000 元，請客戶吃飯10,000元，股東會紀念品20,000元，員工辦公文具用品5,000元，假設營業稅均為外加， 徵收率為百分之五，請問四月份可扣抵進項稅額若干？', '["10,000元", "10,250元", "11,000元", "11,250元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "6211ba8aa6e0", "answer_pdf_sha1": "351af3accf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01268', 'cpa', 'cpa-moex-104-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '某甲出售自用住宅用地，申報移轉現值為100萬元，繳納土地增值稅10萬元，二年內又重購自用住宅用 地，取得時，申報移轉現值為95萬元，其可申請退還之土地增值稅額為多少元？', '["5萬元", "10萬元", "20萬元", "30萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "6211ba8aa6e0", "answer_pdf_sha1": "351af3accf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01269', 'cpa', 'cpa-moex-104-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲於100年8月1日向乙購買自用住宅用地，該日完成產權登記，並於100年9月20日向稅捐處申辦自 用住宅用地優惠稅率，則依土地稅法規定，甲該地地價稅優惠稅率自何時開始適用？', '["100年1月1日", "100年8月1日", "100年9月20日", "101年1月1日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "6211ba8aa6e0", "answer_pdf_sha1": "351af3accf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01270', 'cpa', 'cpa-moex-104-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '土地稅法中有關自用住宅用地之規定，下列何者正確？', '["土地所有權人適用自用住宅用地稅率繳納地價稅者，以一處為限", "土地所有權人與其配偶及未成年之受扶養親屬，適用自用住宅用地稅率繳納土地增值稅者，以一次為限", "土地所有權人未於繳納期間屆滿前申請依自用住宅用地稅率課徵土地增值稅，逾期不得補行申請", "土地所有權人出售自用住宅用地後，二年內另購自用住宅用地，得向主管稽徵機關申請退還全部已納 之土地增值稅額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "6211ba8aa6e0", "answer_pdf_sha1": "351af3accf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
